---@param textureName string
---@param screenX number
---@param screenY number
---@param width number
---@param height number
---@param heading number
---@param red integer
---@param green integer
---@param blue integer
---@param alpha integer
---@param p11 boolean
function DrawSprite(textureDict, textureName, screenX, screenY, width, height, heading, red, green, blue, alpha, p11) end

